const item = $input.item.json;
const finalText = item.edited_text || item.draft_text || '';
const approvalId = item.id;
const destination = item.approved_destination || '';
const sourceUrl = item.source_url || '';
const platform = item.source_platform || '';
const postType = item.approved_post_type || '';

// Sanitize backticks so they don't break the code fence
const safeText = String(finalText).replace(/```/g, '` ` `');

const blocks = [
  {type: 'section', text: {type: 'mrkdwn', text: 
    `:outbox_tray: *Approval #${approvalId} ready to paste*\n` +
    `*Destination:* \`${destination}\`` + (postType ? ` (post type: \`${postType}\`)` : '') + `\n` +
    `*Source:* <${sourceUrl}|${platform || 'view source'}>`}},
  {type: 'divider'},
  {type: 'section', text: {type: 'mrkdwn', text: '```' + safeText + '```'}},
];

return [{json: {
  ...item,
  final_text: finalText,
  slack_blocks: blocks,
  slack_text_fallback: `Approval #${approvalId} ready to paste — ${destination}`,
}}];
